import logging
import json
import os
import uuid
from datetime import datetime

import azure.functions as func
from azure.storage.blob import BlobClient
from azure.cosmos import CosmosClient
from azure.eventgrid import EventGridPublisherClient
from azure.core.credentials import AzureManagedIdentityCredential

app = func.FunctionApp(http_auth_level=func.AuthLevel.FUNCTION)

# --- Configuration ---
# Use environment variables for all configurations
COSMOS_DB_ENDPOINT = os.environ["COSMOS_DB_ENDPOINT"]
COSMOS_DB_DATABASE_ID = os.environ.get("COSMOS_DB_DATABASE_ID", "FileProcessingDB")
COSMOS_DB_CONTAINER_ID = os.environ.get("COSMOS_DB_CONTAINER_ID", "ProcessedFiles")
EVENT_GRID_TOPIC_ENDPOINT = os.environ["EVENT_GRID_TOPIC_ENDPOINT"]

# Initialize credential outside the main function for efficiency
# Managed Identity will be used implicitly if AZURE_CLIENT_ID, AZURE_TENANT_ID, AZURE_FEDERATED_TOKEN_FILE are not set
# It will look for the default identity provided by the Azure Functions host
credential = AzureManagedIdentityCredential()

@app.blob_trigger(
    name="inputblob",
    path="input-files/{name}",
    connection="AzureWebJobsStorage" # This uses the built-in storage account configured for the function app
)
async def process_blob_and_notify(inputblob: func.InputStream):
    logging.info(f"Python blob trigger function processed blob: {inputblob.name}")

    try:
        # --- 1. Read Blob Content ---
        file_content = await inputblob.read()
        content_str = file_content.decode('utf-8') # Assuming text files
        file_size_bytes = len(file_content)

        logging.info(f"Blob {inputblob.name} content read. Size: {file_size_bytes} bytes.")

        # --- 2. Process Content (Example: Simple metadata extraction) ---
        processing_result = {
            "id": str(uuid.uuid4()), # Unique ID for Cosmos DB
            "blob_name": inputblob.name,
            "blob_uri": inputblob.uri,
            "container_name": inputblob.name.split('/')[0],
            "file_name": inputblob.name.split('/')[-1],
            "processed_timestamp": datetime.utcnow().isoformat() + "Z",
            "file_size_bytes": file_size_bytes,
            "first_100_chars": content_str[:100] if len(content_str) > 0 else "",
            "processing_status": "Success",
            "message": "File processed successfully."
        }
        logging.info(f"Processing complete for {inputblob.name}.")

        # --- 3. Write Result to Cosmos DB ---
        cosmos_client = CosmosClient(url=COSMOS_DB_ENDPOINT, credential=credential)
        database = cosmos_client.get_database_client(COSMOS_DB_DATABASE_ID)
        container = database.get_container_client(COSMOS_DB_CONTAINER_ID)

        # Create database and container if they don't exist (for MVP)
        try:
            database.create_if_not_exists()
        except Exception as e:
            logging.warning(f"Could not create database {COSMOS_DB_DATABASE_ID}: {e}")

        try:
            container.create_if_not_exists(partition_key={"paths": ["/blob_name"]}) # Using blob_name as partition key
        except Exception as e:
            logging.warning(f"Could not create container {COSMOS_DB_CONTAINER_ID}: {e}")

        await container.create_item(body=processing_result)
        logging.info(f"Result for {inputblob.name} written to Cosmos DB with ID: {processing_result['id']}.")

        # --- 4. Send Notification via Event Grid ---
        event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)

        event_data = {
            "id": str(uuid.uuid4()),
            "topic": os.environ.get("EVENT_GRID_TOPIC_NAME", "/subscriptions/{subscription-id}/resourceGroups/{resource-group}/providers/Microsoft.EventGrid/topics/{topic-name}"), # Placeholder, but often not needed for simple events
            "subject": f"files/processed/{processing_result['file_name']}",
            "data": {
                "blobUri": inputblob.uri,
                "fileName": processing_result['file_name'],
                "cosmosDbItemId": processing_result['id'],
                "status": processing_result['processing_status'],
                "timestamp": processing_result['processed_timestamp']
            },
            "eventType": "com.example.fileprocessed",
            "dataVersion": "1.0"
        }

        # Event Grid Publisher Client expects a list of events
        await event_grid_client.send([event_data])
        logging.info(f"Event Grid notification sent for {inputblob.name}.")

    except Exception as e:
        logging.error(f"Error processing blob {inputblob.name}: {e}", exc_info=True)
        # Optionally, send a failure notification to Event Grid
        error_event_data = {
            "id": str(uuid.uuid4()),
            "topic": os.environ.get("EVENT_GRID_TOPIC_NAME", "/subscriptions/{subscription-id}/resourceGroups/{resource-group}/providers/Microsoft.EventGrid/topics/{topic-name}"),
            "subject": f"files/failed/{inputblob.name.split('/')[-1]}",
            "data": {
                "blobUri": inputblob.uri,
                "fileName": inputblob.name.split('/')[-1],
                "status": "Failed",
                "errorMessage": str(e),
                "timestamp": datetime.utcnow().isoformat() + "Z"
            },
            "eventType": "com.example.fileprocessingfailed",
            "dataVersion": "1.0"
        }
        try:
            event_grid_client = EventGridPublisherClient(endpoint=EVENT_GRID_TOPIC_ENDPOINT, credential=credential)
            await event_grid_client.send([error_event_data])
            logging.info(f"Failure Event Grid notification sent for {inputblob.name}.")
        except Exception as ee:
            logging.error(f"Failed to send failure notification for {inputblob.name}: {ee}", exc_info=True)

